import React, { useState } from 'react';
import axios from 'axios';
import './css/style.css';

function Auth({ setToken }) {
  const [isLogin, setIsLogin] = useState(true);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!username || !password) return alert("Заполните поля");

    const url = `http://localhost:5000/api/auth/${isLogin ? 'login' : 'register'}`;
    
    try {
      const res = await axios.post(url, { username, password });
      
      if (isLogin) {
        if (res.data.token) {
          setToken(res.data.token);
        }
      } else {
        alert("Регистрация успешна! Войдите.");
        setIsLogin(true);
      }
    } catch (err) {
      const message = err.response?.data?.message || err.response?.data?.error || "Ошибка сервера";
      alert("Ошибка: " + message);
    }
  };

  return (
    <div className="auth-wrapper">
      <div className="auth-card">
        <h2 className="auth-title">{isLogin ? 'Вход' : 'Регистрация'}</h2>
        <form onSubmit={handleSubmit} className="auth-form">
          <input 
            className="auth-input"
            type="text"
            placeholder="Username" 
            value={username}
            onChange={e => setUsername(e.target.value)} 
          />
          <input 
            className="auth-input"
            type="password" 
            placeholder="Password" 
            value={password}
            onChange={e => setPassword(e.target.value)} 
          />
          <button className="auth-button" type="submit">
            {isLogin ? 'Войти' : 'Создать аккаунт'}
          </button>
        </form>
        <div className="auth-footer">
          <span>{isLogin ? 'Нет аккаунта?' : 'Уже есть аккаунт?'}</span>
          <button className="auth-toggle" onClick={() => setIsLogin(!isLogin)}>
            {isLogin ? 'Зарегистрироваться' : 'Войти'}
          </button>
        </div>
      </div>
    </div>
  );
}

export default Auth;
